    }

    private fun handleCleanup(intent: Intent) {
        val taskId = intent.getStringExtra(EXTRA_TASK_ID) ?: "unknown"
        val cleanupType = intent.getStringExtra(EXTRA_CLEANUP_TYPE) ?: "temporary"
        
